parameters.jsCode:
// Normalize an incoming alert into a stable incident object.
const body = $input.first().json.body ?? {};

const service = String(body.service ?? 'unknown').trim().toLowerCase();
const level   = String(body.level   ?? 'ERROR').trim().toUpperCase();
const message = String(body.message ?? '').trim();

// A signature is the message with volatile bits (numbers, hex ids, timestamps)
// stripped, so "timeout after 30000ms" and "timeout after 12ms" collapse to one.
const signature = message
  .replace(/\b[0-9a-f]{8,}\b/gi, 'ID')   // hex ids / trace ids
  .replace(/\d+/g, 'N')                  // any run of digits
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 120);

const incident = {
  service,
  level,
  message,
  signature,
  fingerprint: `${service}:${signature}`,
  received_at: new Date().toISOString(),
};

return [{ json: incident }];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "title": { "type": "string", "description": "Short incident title" },
    "service": { "type": "string", "description": "Affected service name" },
    "severity": { "type": "string", "enum": ["low", "medium", "high", "critical"], "description": "Incident severity" },
    "hypothesis": { "type": "string", "description": "Root-cause hypothesis based on evidence" },
    "evidence": { "type": "array", "items": { "type": "string" }, "description": "Specific evidence points: log lines, commits, runbook findings" },
    "recommended_action": { "type": "string", "description": "Concrete recommended next step" },
    "confidence": { "type": "number", "description": "Confidence from 0.0 to 1.0" }
  },
  "required": ["title", "service", "severity", "hypothesis", "evidence", "recommended_action", "confidence"]
}

parameters.query:
UPDATE incidents
   SET github_issue_url = $1
   WHERE fingerprint = $2;
